// Moiré Waves - Op-Art Interference Patterns

let prevParams = '';
let pg;

const PALETTES = {
  black_white: {bg:[0,0,0], fg:[255,255,255], mid:[128,128,128]},
  blueprint: {bg:[10,20,60], fg:[100,180,255], mid:[40,80,160]},
  infrared: {bg:[20,0,0], fg:[255,50,20], mid:[200,100,0]},
  cyberpunk: {bg:[10,0,20], fg:[255,0,200], mid:[0,200,255]},
  gold_black: {bg:[0,0,0], fg:[255,200,50], mid:[180,140,30]},
  acid: {bg:[0,10,0], fg:[0,255,50], mid:[200,255,0]},
  sunset_gradient: {bg:[20,0,40], fg:[255,120,0], mid:[255,50,80]},
  deep_ocean: {bg:[0,5,20], fg:[0,180,200], mid:[0,80,140]}
};

function getWaveN(v) {
  const m = {pair:2, trio:3, quad:4, quintet:5, dense:7, maximal:10};
  return m[v] || 3;
}

function getFreq(v) {
  const m = {low:0.008, medium:0.015, high:0.025, ultra:0.04, mixed:-1, harmonic:-2};
  return m[v] || 0.015;
}

function getOffset(v) {
  const m = {none:0, slight:15, moderate:40, wide:80, opposing:300, chaotic:-1};
  return m[v] || 15;
}

function getThick(v) {
  const m = {hairline:0.35, thin:0.42, medium:0.48, thick:0.55, chunky:0.65, variable:-1};
  return m[v] || 0.42;
}

function getAnimSpeed(v) {
  const m = {frozen:0, glacial:0.003, slow:0.008, medium:0.02, fast:0.05, frantic:0.1};
  return m[v] || 0.008;
}

function applyDistortion(x, y, distType, t, cx, cy) {
  let dx = x - cx, dy = y - cy;
  let dist = Math.sqrt(dx*dx + dy*dy);
  let angle = Math.atan2(dy, dx);
  if (distType === 'ripple') {
    let wave = Math.sin(dist * 0.03 + t * 2) * 15;
    return [x + Math.cos(angle) * wave, y + Math.sin(angle) * wave];
  } else if (distType === 'pinch') {
    let factor = 1 + 0.3 * Math.sin(t);
    let newDist = Math.pow(dist / 300, factor) * 300;
    return [cx + Math.cos(angle) * newDist, cy + Math.sin(angle) * newDist];
  } else if (distType === 'fisheye') {
    let r = dist / 300;
    let newR = r * r;
    return [cx + Math.cos(angle) * newR * 300, cy + Math.sin(angle) * newR * 300];
  } else if (distType === 'shatter') {
    let cell = 80;
    let cx2 = Math.floor(x / cell) * cell + cell/2;
    let cy2 = Math.floor(y / cell) * cell + cell/2;
    let off = Math.sin(cx2 * 0.1 + t) * 10;
    return [x + off, y + Math.cos(cy2 * 0.1 + t) * 10];
  } else if (distType === 'vortex') {
    let twist = dist * 0.004 * Math.sin(t * 0.5);
    return [cx + Math.cos(angle + twist) * dist, cy + Math.sin(angle + twist) * dist];
  }
  return [x, y];
}

p.setup = function() {
  p.createCanvas(600, 600);
  p.frameRate(30);
  p.pixelDensity(1);
};

p.draw = function() {
  let waveNV = p.getSynthVar('wave_count') || 'trio';
  let shapeV = p.getSynthVar('wave_shape') || 'concentric';
  let freqV = p.getSynthVar('wave_frequency') || 'medium';
  let offsetV = p.getSynthVar('layer_offset') || 'moderate';
  let rotV = p.getSynthVar('rotation_mode') || 'slow_spin';
  let thickV = p.getSynthVar('line_thickness') || 'thin';
  let palV = p.getSynthVar('color_palette') || 'black_white';
  let blendV = p.getSynthVar('color_blend') || 'multiply';
  let speedV = p.getSynthVar('animation_speed') || 'slow';
  let distV = p.getSynthVar('distortion') || 'none';

  let nWaves = getWaveN(waveNV);
  let baseFreq = getFreq(freqV);
  let layerOff = getOffset(offsetV);
  let threshold = getThick(thickV);
  let animSpeed = getAnimSpeed(speedV);
  let pal = PALETTES[palV] || PALETTES.black_white;
  let t = p.frameCount * animSpeed;

  p.loadPixels();
  let cx = 300, cy = 300;

  for (let py = 0; py < 600; py += 1) {
    for (let px = 0; px < 600; px += 1) {
      let x = px, y = py;

      // Apply distortion
      if (distV !== 'none') {
        let d = applyDistortion(x, y, distV, t, cx, cy);
        x = d[0]; y = d[1];
      }

      let totalVal = 0;

      for (let w = 0; w < nWaves; w++) {
        let offX = 0, offY = 0;
        let rot = 0;

        // Layer offset
        if (layerOff === -1) {
          offX = Math.sin(w * 7.3) * 100;
          offY = Math.cos(w * 5.1) * 100;
        } else if (offsetV === 'opposing') {
          let angle = w * Math.PI / nWaves;
          offX = Math.cos(angle) * layerOff;
          offY = Math.sin(angle) * layerOff;
        } else {
          offX = w * layerOff;
          offY = w * layerOff * 0.5;
        }

        // Rotation
        if (rotV === 'slow_spin') rot = t * 0.5 + w * 0.3;
        else if (rotV === 'counter') rot = t * 0.5 * (w % 2 === 0 ? 1 : -1);
        else if (rotV === 'breathe') rot = Math.sin(t + w) * 0.5;
        else if (rotV === 'pendulum') rot = Math.sin(t * 0.3) * 1.2 + w * 0.2;
        else if (rotV === 'cascade') rot = w * 0.3 + t * 0.3;

        let lx = x - cx - offX;
        let ly = y - cy - offY;
        let rx = lx * Math.cos(rot) - ly * Math.sin(rot);
        let ry = lx * Math.sin(rot) + ly * Math.cos(rot);

        let freq = baseFreq;
        if (baseFreq === -1) freq = 0.01 + w * 0.005;
        else if (baseFreq === -2) freq = baseFreq * (w + 1);

        let val;
        if (shapeV === 'sine') {
          val = Math.sin(rx * freq + t);
        } else if (shapeV === 'concentric') {
          let d = Math.sqrt(rx*rx + ry*ry);
          val = Math.sin(d * freq + t);
        } else if (shapeV === 'linear') {
          val = Math.sin((rx * Math.cos(w) + ry * Math.sin(w)) * freq + t);
        } else if (shapeV === 'radial') {
          let a = Math.atan2(ry, rx);
          val = Math.sin(a * (3 + w * 2) + t);
        } else if (shapeV === 'spiral') {
          let d = Math.sqrt(rx*rx + ry*ry);
          let a = Math.atan2(ry, rx);
          val = Math.sin(d * freq + a * 3 + t);
        } else { // chevron
          val = Math.sin((Math.abs(rx) + Math.abs(ry)) * freq + t);
        }

        // Blend
        let normVal = (val + 1) * 0.5; // 0-1
        if (blendV === 'multiply') totalVal += normVal;
        else if (blendV === 'screen') totalVal = 1 - (1 - totalVal) * (1 - normVal);
        else if (blendV === 'difference') totalVal += Math.abs(normVal - 0.5);
        else if (blendV === 'overlay') totalVal += normVal > 0.5 ? 1 - 2*(1-normVal)*(1-totalVal/Math.max(1,w)) : 2*normVal*(totalVal/Math.max(1,w));
        else if (blendV === 'xor') totalVal = (totalVal + normVal) % 1.0 + (totalVal + normVal > 1 ? 0.5 : 0);
        else totalVal += normVal; // additive
      }

      // Normalize
      if (blendV === 'multiply' || blendV === 'additive') totalVal /= nWaves;
      totalVal = Math.max(0, Math.min(1, totalVal));

      // Variable line thickness
      if (threshold === -1) {
        threshold = 0.35 + Math.sin(px * 0.01 + py * 0.01) * 0.15;
      }

      // Apply threshold for sharp moiré lines
      let bright = totalVal > threshold ? 1 : 0;
      // Smooth edge
      let edge = Math.abs(totalVal - threshold);
      if (edge < 0.05) bright = totalVal > threshold ? 1 - (0.05 - edge) * 10 : (0.05 - edge) * 10;

      let r, g, b;
      if (bright > 0.5) {
        let f = (bright - 0.5) * 2;
        r = pal.mid[0] + (pal.fg[0] - pal.mid[0]) * f;
        g = pal.mid[1] + (pal.fg[1] - pal.mid[1]) * f;
        b = pal.mid[2] + (pal.fg[2] - pal.mid[2]) * f;
      } else {
        let f = bright * 2;
        r = pal.bg[0] + (pal.mid[0] - pal.bg[0]) * f;
        g = pal.bg[1] + (pal.mid[1] - pal.bg[1]) * f;
        b = pal.bg[2] + (pal.mid[2] - pal.bg[2]) * f;
      }

      let idx = (py * 600 + px) * 4;
      p.pixels[idx] = r;
      p.pixels[idx+1] = g;
      p.pixels[idx+2] = b;
      p.pixels[idx+3] = 255;
    }
  }
  p.updatePixels();
};
